	"wms_include_items" "all"
	"wms_exclude_items" "value_0,red,green,blue"
	"force_imagetype" "jpeg"
  END
  CLASS
	NAME "Evapotranspiración real (mm)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "38 - 50"
    EXPRESSION ([pixel] >= 38 AND [pixel] < 50)
    COLOR 54 145 33
  END
  CLASS
	NAME "50 - 60"
    EXPRESSION ([pixel] >= 50 AND [pixel] < 60)
    COLOR 149 199 105
  END
  CLASS
	NAME "60 - 70"
    EXPRESSION ([pixel] >= 60 AND [pixel] < 70)
    COLOR 102 217 129
  END
  CLASS
	NAME "70 - 90"
    EXPRESSION ([pixel] >= 70 AND [pixel] < 90)
    COLOR 204 230 76
  END
  CLASS
	NAME "90 - 110"
    EXPRESSION ([pixel] >= 90 AND [pixel] < 110)
    COLOR 235 255 153
  END
  CLASS
	NAME "110 - 130"
    EXPRESSION ([pixel] >= 110 AND [pixel] < 130)
    COLOR 250 250 95
  END
  CLASS
	NAME "130 - 140"
    EXPRESSION ([pixel] >= 130 AND [pixel] < 140)
    COLOR 255 208 0
  END
  CLASS
	NAME "140 - 150"
    EXPRESSION ([pixel] >= 140 AND [pixel] < 150)
    COLOR 255 134 128
  END
  CLASS
	NAME "150 - 160"
    EXPRESSION ([pixel] >= 150 AND [pixel] <= 170)
    COLOR 230 101 127
  END
END # Layer